export const isJsxOrTsx = (filePath) => {
    if (!filePath)
        return false;
    const lower = filePath.toLowerCase();
    return lower.endsWith('.jsx') || lower.endsWith('.tsx');
};
export const isTsxFile = (filePath) => {
    if (!filePath)
        return false;
    return filePath.toLowerCase().endsWith('.tsx');
};
